#!/usr/bin/env node
// Auto-generated by the Klar React generator. Do not edit by hand.
//
// Build-time formula expander for src/config/form-enhancements/*.ts.
// The sandbox sub-agent writes `computed` entries as compact formula strings:
//
//   computed: {
//     arbeitskosten: 'applookup(mitarbeiter, stundensatz) * field(arbeitsstunden)',
//   }
//
// This script (run AFTER the sub-agent finishes and BEFORE `npm run build`)
// rewrites those strings into the runtime spec-tree literals the dialog
// renderer actually evaluates:
//
//   computed: {
//     arbeitskosten: { op: 'mul',
//       left:  { kind: 'applookup', ownKey: 'mitarbeiter', lookupKey: 'stundensatz' },
//       right: { kind: 'field', key: 'arbeitsstunden' } },
//   }
//
// MODUS-2 entries (arrow functions) are left untouched. Parse failures are
// dropped silently â€” a missing computed is better than a broken build.
//
// Mini-DSL grammar (recursive descent):
//   expr   := term (('+' | '-') term)*
//   term   := factor (('*' | '/') factor)*
//   factor := number | call | '(' expr ')'
//   call   := IDENT '(' (arg (',' arg)*)? ')'
//   arg    := IDENT | number
// Supported calls:
//   field(key)
//   literal(value)
//   applookup(ownKey, lookupKey)
//   dateDiff(fromKey, toKey, days|hours)
// Bare numbers are also accepted as literals.

import { readdir, readFile, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

const TARGET_DIR = 'src/config/form-enhancements';

// ---------------------------------------------------------------- tokenizer
function tokenize(src) {
  const tokens = [];
  let i = 0;
  while (i < src.length) {
    const c = src[i];
    if (c === ' ' || c === '\t' || c === '\n' || c === '\r') { i++; continue; }
    if (c === '(' || c === ')' || c === ',') {
      tokens.push({ type: c === '(' ? 'LPAREN' : c === ')' ? 'RPAREN' : 'COMMA' });
      i++; continue;
    }
    if (c === '+' || c === '-' || c === '*' || c === '/') {
      tokens.push({ type: 'OP', value: c });
      i++; continue;
    }
    if ((c >= '0' && c <= '9') || c === '.') {
      let j = i;
      while (j < src.length && ((src[j] >= '0' && src[j] <= '9') || src[j] === '.')) j++;
      const num = Number(src.slice(i, j));
      if (!Number.isFinite(num)) throw new Error(`bad number at ${i}: ${src.slice(i, j)}`);
      tokens.push({ type: 'NUMBER', value: num });
      i = j; continue;
    }
    if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || c === '_') {
      let j = i;
      while (j < src.length && /[A-Za-z0-9_]/.test(src[j])) j++;
      tokens.push({ type: 'IDENT', value: src.slice(i, j) });
      i = j; continue;
    }
    throw new Error(`unexpected char '${c}' at ${i}`);
  }
  return tokens;
}

// ------------------------------------------------------------------ parser
function parseFormula(src) {
  const tokens = tokenize(src);
  let pos = 0;
  const peek = () => tokens[pos];
  const eat = (type) => {
    const t = tokens[pos];
    if (!t || t.type !== type) throw new Error(`expected ${type}, got ${t ? t.type : 'EOF'}`);
    pos++; return t;
  };

  function parseExpr() {
    let left = parseTerm();
    while (peek() && peek().type === 'OP' && (peek().value === '+' || peek().value === '-')) {
      const op = eat('OP').value === '+' ? 'add' : 'sub';
      const right = parseTerm();
      left = { op, left, right };
    }
    return left;
  }
  function parseTerm() {
    let left = parseFactor();
    while (peek() && peek().type === 'OP' && (peek().value === '*' || peek().value === '/')) {
      const op = eat('OP').value === '*' ? 'mul' : 'div';
      const right = parseFactor();
      left = { op, left, right };
    }
    return left;
  }
  function parseFactor() {
    const t = peek();
    if (!t) throw new Error('unexpected EOF');
    if (t.type === 'NUMBER') { eat('NUMBER'); return { kind: 'literal', value: t.value }; }
    if (t.type === 'LPAREN') { eat('LPAREN'); const e = parseExpr(); eat('RPAREN'); return e; }
    if (t.type === 'IDENT') {
      const name = eat('IDENT').value;
      eat('LPAREN');
      const args = [];
      if (peek() && peek().type !== 'RPAREN') {
        args.push(eat(peek().type));
        while (peek() && peek().type === 'COMMA') { eat('COMMA'); args.push(eat(peek().type)); }
      }
      eat('RPAREN');
      if (name === 'field') {
        if (args.length !== 1 || args[0].type !== 'IDENT') throw new Error('field(key) needs 1 ident');
        return { kind: 'field', key: args[0].value };
      }
      if (name === 'literal') {
        if (args.length !== 1 || args[0].type !== 'NUMBER') throw new Error('literal(n) needs 1 number');
        return { kind: 'literal', value: args[0].value };
      }
      if (name === 'applookup') {
        if (args.length !== 2 || args[0].type !== 'IDENT' || args[1].type !== 'IDENT')
          throw new Error('applookup(own, key) needs 2 idents');
        return { kind: 'applookup', ownKey: args[0].value, lookupKey: args[1].value };
      }
      if (name === 'dateDiff') {
        if (args.length < 2 || args[0].type !== 'IDENT' || args[1].type !== 'IDENT')
          throw new Error('dateDiff needs from, to, unit');
        const unit = args[2] && args[2].type === 'IDENT' ? args[2].value : 'days';
        if (unit !== 'days' && unit !== 'hours') throw new Error(`bad unit: ${unit}`);
        return { kind: 'dateDiff', from: args[0].value, to: args[1].value, unit };
      }
      throw new Error(`unknown function: ${name}`);
    }
    throw new Error(`unexpected token ${t.type}`);
  }

  const tree = parseExpr();
  if (pos !== tokens.length) throw new Error(`extra tokens at ${pos}`);
  return tree;
}

// ------------------------------------------------------- spec-tree renderer
function renderTree(node) {
  if ('op' in node) {
    return `{ op: '${node.op}', left: ${renderTree(node.left)}, right: ${renderTree(node.right)} }`;
  }
  if (node.kind === 'literal') return `{ kind: 'literal', value: ${node.value} }`;
  if (node.kind === 'field') return `{ kind: 'field', key: '${node.key}' }`;
  if (node.kind === 'applookup') {
    return `{ kind: 'applookup', ownKey: '${node.ownKey}', lookupKey: '${node.lookupKey}' }`;
  }
  if (node.kind === 'dateDiff') {
    return `{ kind: 'dateDiff', from: '${node.from}', to: '${node.to}', unit: '${node.unit}' }`;
  }
  throw new Error(`cannot render ${JSON.stringify(node)}`);
}

// --------------------------------------------------- computed-block scanner
//
// Locates `computed: { ... }` in a config file, splits the body into entries,
// rewrites each string-valued entry to a spec-tree literal, and returns the
// updated source. Entries that fail to parse are dropped silently.
//
// We do a balanced-brace scan rather than a full TS parser. The block is
// shallow (no nested objects beyond what the spec-trees already produce) and
// arrow functions only appear at entry level, so depth tracking + string-
// literal awareness is enough.

function findComputedBlock(src) {
  const m = src.match(/computed\s*:\s*\{/);
  if (!m) return null;
  const openIdx = m.index + m[0].length - 1; // position of '{'
  let depth = 0, i = openIdx, inStr = null, esc = false;
  while (i < src.length) {
    const c = src[i];
    if (inStr) {
      if (esc) { esc = false; }
      else if (c === '\\') { esc = true; }
      else if (c === inStr) { inStr = null; }
      i++; continue;
    }
    if (c === '"' || c === "'" || c === '`') { inStr = c; i++; continue; }
    if (c === '{') { depth++; i++; continue; }
    if (c === '}') { depth--; if (depth === 0) return { open: openIdx, close: i }; i++; continue; }
    i++;
  }
  return null;
}

function stripComments(s) {
  // Strip `//` line comments and `/* â€¦ */` block comments that sit outside
  // string literals. Sub-agents sometimes annotate computed entries with
  // inline comments â€” keeping them would break the entry-splitter and the
  // key/value regex, causing the formula to be silently dropped.
  let out = '';
  let i = 0, inStr = null, esc = false;
  while (i < s.length) {
    const c = s[i], n = s[i + 1];
    if (inStr) {
      if (esc) esc = false;
      else if (c === '\\') esc = true;
      else if (c === inStr) inStr = null;
      out += c; i++; continue;
    }
    if (c === '"' || c === "'" || c === '`') { inStr = c; out += c; i++; continue; }
    if (c === '/' && n === '/') {
      while (i < s.length && s[i] !== '\n') i++;
      continue;
    }
    if (c === '/' && n === '*') {
      i += 2;
      while (i < s.length - 1 && !(s[i] === '*' && s[i + 1] === '/')) i++;
      i += 2; continue;
    }
    out += c; i++;
  }
  return out;
}

function splitEntries(body) {
  // Split top-level entries (`key: value,`) by commas that sit at depth 0
  // and outside string literals. Returns array of raw entry strings (trimmed).
  const out = [];
  let depth = 0, inStr = null, esc = false, start = 0;
  for (let i = 0; i < body.length; i++) {
    const c = body[i];
    if (inStr) {
      if (esc) { esc = false; }
      else if (c === '\\') { esc = true; }
      else if (c === inStr) { inStr = null; }
      continue;
    }
    if (c === '"' || c === "'" || c === '`') { inStr = c; continue; }
    if (c === '{' || c === '(' || c === '[') { depth++; continue; }
    if (c === '}' || c === ')' || c === ']') { depth--; continue; }
    if (c === ',' && depth === 0) {
      const e = body.slice(start, i).trim();
      if (e) out.push(e);
      start = i + 1;
    }
  }
  const last = body.slice(start).trim();
  if (last) out.push(last);
  return out;
}

function parseEntry(entry) {
  // Returns { key, value } where value is the raw RHS source (trimmed).
  // Supports keys as bare ident or single/double quoted.
  const m = entry.match(/^\s*(?:(['"`])([^'"`]+)\1|([A-Za-z_$][A-Za-z0-9_$]*))\s*:\s*([\s\S]+)$/);
  if (!m) return null;
  const key = m[2] || m[3];
  return { key, value: m[4].trim() };
}

// ---------------------------- MODUS-2 function dep extraction (regex)
//
// MODUS-2 arrow functions are opaque to the runtime's extractFieldDeps walk.
// To still anchor them inline under the right input, we regex the function
// source for ctx.* helper calls with string-literal arguments and surface
// the field keys as `computedDeps[key] = [...]`. The dialog uses this map
// to drive classifyComputed.
//
// Limitations (intentional â€” see HANDOFF Phase 2 notes):
//   â€˘ Misses destructured calls like `const { field } = ctx; field('x')`.
//   â€˘ Misses variable-indirected keys like `const k = 'x'; ctx.field(k)`.
//   â€˘ Comments containing fake ctx.* calls would yield false positives.
// Prompt hygiene keeps these cases out of typical sub-agent output; if a
// dep is missed, the only consequence is a missing inline hint â€” the
// computation itself still runs correctly via the live function.

function extractDepsFromFunction(fnStr) {
  const deps = new Set();
  const singleArg = [
    /ctx\.field\(\s*['"`]([^'"`]+)['"`]/g,
    /ctx\.applookup\w*\(\s*['"`]([^'"`]+)['"`]/g,
    /ctx\.lookupKey\(\s*['"`]([^'"`]+)['"`]/g,
    /ctx\.sumOver\(\s*['"`]([^'"`]+)['"`]/g,
    /ctx\.addDays\(\s*['"`]([^'"`]+)['"`]/g,
  ];
  for (const re of singleArg) {
    for (const m of fnStr.matchAll(re)) deps.add(m[1]);
  }
  // dateDiff(from, to, unit?) â€” two field args.
  const dateDiffRe = /ctx\.dateDiff\(\s*['"`]([^'"`]+)['"`]\s*,\s*['"`]([^'"`]+)['"`]/g;
  for (const m of fnStr.matchAll(dateDiffRe)) { deps.add(m[1]); deps.add(m[2]); }
  return [...deps];
}

/**
 * Extract (ownKey, lookupKey) pairs from `ctx.applookup('x','y')` and
 * `ctx.applookupAny('x','y')` calls in a MODUS-2 function body. Used to
 * surface inline reference hints next to the applookup combobox so the
 * user sees WHICH numeric field the formula will pull when the lookup
 * resolves.
 *
 * Limitations match extractDepsFromFunction:
 *   â€˘ Misses destructured calls (`const { applookup } = ctx; applookup(â€¦)`).
 *   â€˘ Misses variable-indirected keys (`applookup(k, l)` with non-literal k/l).
 * The only consequence of a miss is a missing hint â€” the formula still
 * runs correctly via the live function.
 */
function extractApplookupRefsFromFunction(fnStr) {
  const pairs = [];
  const re = /ctx\.applookup\w*\(\s*['"`]([^'"`]+)['"`]\s*,\s*['"`]([^'"`]+)['"`]/g;
  for (const m of fnStr.matchAll(re)) pairs.push({ ownKey: m[1], lookupKey: m[2] });
  return pairs;
}

function renderDepsExport(map) {
  const keys = Object.keys(map);
  if (keys.length === 0) {
    return 'export const computedDeps: Record<string, string[]> = {};';
  }
  const lines = keys.map(k => {
    const list = map[k].map(d => `'${d}'`).join(', ');
    return `  '${k}': [${list}],`;
  });
  return 'export const computedDeps: Record<string, string[]> = {\n'
    + lines.join('\n') + '\n};';
}

// Dedup the merged MODUS-2 applookup-refs map per (ownKey, lookupKey) and
// render as `export const computedApplookupRefs: Record<string, {lookupKey:
// string}[]> = { ... };`. Returns the empty-record line when nothing was
// found â€” the dialog merges this with MODUS-1 refs at runtime.
function renderApplookupRefsExport(map) {
  const ownKeys = Object.keys(map);
  if (ownKeys.length === 0) {
    return 'export const computedApplookupRefs: Record<string, {lookupKey: string}[]> = {};';
  }
  const lines = ownKeys.map(ownKey => {
    const seen = new Set();
    const items = [];
    for (const ref of map[ownKey]) {
      if (seen.has(ref.lookupKey)) continue;
      seen.add(ref.lookupKey);
      items.push(`{ lookupKey: '${ref.lookupKey}' }`);
    }
    return `  '${ownKey}': [${items.join(', ')}],`;
  });
  return 'export const computedApplookupRefs: Record<string, {lookupKey: string}[]> = {\n'
    + lines.join('\n') + '\n};';
}

// Replace the existing `export const computedDeps ... = { ... };` (skeleton-
// generated) with the freshly-built one, or append if missing. The type
// annotation `: Record<string, string[]>` is optional â€” Haiku sometimes
// rewrites the file with just `export const computedDeps = {};` and we
// must still recognise and replace it, otherwise we'd append a duplicate
// and TypeScript bails with TS2451 (redeclare block-scoped variable).
function patchDepsExport(src, depsSrc) {
  const re = /export\s+const\s+computedDeps\s*(?::\s*Record\s*<[^>]+>\s*)?=\s*\{[\s\S]*?\};?/;
  if (re.test(src)) return src.replace(re, depsSrc);
  return src.trimEnd() + '\n\n' + depsSrc + '\n';
}

// Same idea for computedApplookupRefs â€” replace skeleton-generated stub if
// present, otherwise append. Type annotation is tolerated as Sub-Agent or
// other tooling may rewrite the file to a simpler `export const ... = {};`.
function patchApplookupRefsExport(src, refsSrc) {
  const re = /export\s+const\s+computedApplookupRefs\s*(?::\s*Record\s*<[^>]+>\s*)?=\s*\{[\s\S]*?\};?/;
  if (re.test(src)) return src.replace(re, refsSrc);
  return src.trimEnd() + '\n\n' + refsSrc + '\n';
}

function rewriteFile(src) {
  const block = findComputedBlock(src);
  if (!block) return { src, changed: false, count: 0, deps: 0 };
  const body = stripComments(src.slice(block.open + 1, block.close));
  const entries = splitEntries(body);
  if (entries.length === 0) return { src, changed: false, count: 0, deps: 0 };

  const out = [];
  const funcDeps = {};
  const funcApplookupRefs = {};  // ownKey â†’ [{lookupKey}, ...]
  let dropped = 0, parsed = 0;
  for (const raw of entries) {
    const ent = parseEntry(raw);
    if (!ent) { dropped++; continue; }
    const v = ent.value;
    // String literal â†’ parse formula and expand.
    if (v.startsWith("'") || v.startsWith('"') || v.startsWith('`')) {
      const quote = v[0];
      const end = v.lastIndexOf(quote);
      if (end <= 0) { dropped++; continue; }
      const formula = v.slice(1, end);
      try {
        const tree = parseFormula(formula);
        out.push(`    '${ent.key}': ${renderTree(tree)}`);
        parsed++;
      } catch (err) {
        console.warn(`[parse-formulas] dropped ${ent.key}: ${err.message} (formula: ${formula})`);
        dropped++;
      }
      continue;
    }
    // Arrow function â€” leave the body alone, but mine it for ctx.* deps
    // AND for applookup (ownKey, lookupKey) pairs.
    out.push(`    '${ent.key}': ${v}`);
    if (v.startsWith('(') || v.startsWith('async')) {
      const deps = extractDepsFromFunction(v);
      if (deps.length > 0) funcDeps[ent.key] = deps;
      const refs = extractApplookupRefsFromFunction(v);
      for (const r of refs) {
        (funcApplookupRefs[r.ownKey] ||= []).push({ lookupKey: r.lookupKey });
      }
    }
  }
  const hasFuncDeps = Object.keys(funcDeps).length > 0;
  const hasApplookupRefs = Object.keys(funcApplookupRefs).length > 0;
  if (parsed === 0 && dropped === 0 && !hasFuncDeps && !hasApplookupRefs) {
    return { src, changed: false, count: 0, deps: 0, applookupRefs: 0 };
  }

  const rendered = '{\n' + out.join(',\n') + (out.length ? ',\n  ' : '  ') + '}';
  let updated = src.slice(0, block.open) + rendered + src.slice(block.close + 1);
  updated = patchDepsExport(updated, renderDepsExport(funcDeps));
  updated = patchApplookupRefsExport(updated, renderApplookupRefsExport(funcApplookupRefs));
  return {
    src: updated, changed: true, count: parsed, dropped,
    deps: Object.keys(funcDeps).length,
    applookupRefs: Object.keys(funcApplookupRefs).length,
  };
}

// ----------------------------------------------------------------- driver
async function main() {
  let files;
  try { files = await readdir(TARGET_DIR); }
  catch { console.log(`[parse-formulas] no ${TARGET_DIR}/ â€” nothing to do`); return; }

  const targets = files.filter(f => f.endsWith('.ts') && f !== 'types.ts');
  if (targets.length === 0) { console.log('[parse-formulas] no entity configs found'); return; }

  let totalParsed = 0, totalDropped = 0, totalDeps = 0, totalRefs = 0, touched = 0;
  for (const name of targets) {
    const path = join(TARGET_DIR, name);
    let src;
    try { src = await readFile(path, 'utf8'); }
    catch (err) { console.warn(`[parse-formulas] skip ${name}: ${err.message}`); continue; }
    let res;
    try { res = rewriteFile(src); }
    catch (err) { console.warn(`[parse-formulas] error in ${name}: ${err.message}`); continue; }
    if (!res.changed) continue;
    await writeFile(path, res.src, 'utf8');
    totalParsed += res.count;
    totalDropped += res.dropped || 0;
    totalDeps += res.deps || 0;
    totalRefs += res.applookupRefs || 0;
    touched++;
    console.log(`[parse-formulas] ${name}: ${res.count} expanded, ${res.dropped || 0} dropped, ${res.deps || 0} fn-deps, ${res.applookupRefs || 0} applookup-refs`);
  }
  console.log(`[parse-formulas] done â€” ${touched} files, ${totalParsed} formulas, ${totalDropped} dropped, ${totalDeps} fn-deps, ${totalRefs} applookup-refs`);
}

main().catch(err => { console.error('[parse-formulas] fatal:', err); process.exit(0); });
